arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now sets the UTF-8 EFS flag for
        // non-ASCII entry names. The legacy Java consumer expects Shift-JIS, so
        // specify the encoding explicitly to avoid the EFS flag.
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create,
            Encoding.GetEncoding("Shift_JIS"));
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// .NET 9 breaking change: [FromKeyedServices("cache")] now throws if the
// service is registered as non-keyed. Register with the matching key.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

